import { ipcMain } from 'electron';
import { githubActionsService } from '../services/GitHubActionsService';
import { z } from 'zod';
import { ApiResult } from './types';
import { licenseService } from '../services/LicenseService';

// Zod schemas for validation
const enableGitHubActionsSchema = z.object({
  serverId: z.string(),
  appName: z.string(),
  repoOwner: z.string(),
  repoName: z.string(),
  branch: z.string(),
  workingDirectory: z.string(),
  installCommand: z.string(),
  buildCommand: z.string(),
});

const disableGitHubActionsSchema = z.object({
  serverId: z.string(),
  appName: z.string(),
});

const getConfigSchema = z.object({
  serverId: z.string(),
  appName: z.string(),
});

const getWorkflowRunsSchema = z.object({
  serverId: z.string(),
  appName: z.string(),
  perPage: z.number().optional(),
  page: z.number().optional(),
});

const triggerManualDeploySchema = z.object({
  serverId: z.string(),
  appName: z.string(),
});

const syncWorkflowSchema = z.object({
  serverId: z.string(),
  appName: z.string(),
});

const updateConfigSchema = z.object({
  serverId: z.string(),
  appName: z.string(),
  updates: z.object({
    branch: z.string().optional(),
    workingDirectory: z.string().optional(),
    installCommand: z.string().optional(),
    buildCommand: z.string().optional(),
  }),
});

// TypeScript interfaces for return types
interface GitHubActionsConfig {
  id: string;
  server_id: string;
  app_name: string;
  repo_owner: string;
  repo_name: string;
  branch: string;
  working_directory: string;
  install_command: string;
  build_command: string;
  ssh_key_path: string;
  workflow_file_sha: string | null;
  is_active: number;
  created_at: number;
  updated_at: number;
}

interface WorkflowRun {
  id: number;
  name: string;
  status: string;
  conclusion: string | null;
  created_at: string;
  updated_at: string;
  html_url: string;
  head_sha: string;
  head_branch: string;
}

export function registerGitHubActionsHandlers() {
  // Enable GitHub Actions deployment
  ipcMain.handle('github-actions:enable', async (_event, params): Promise<ApiResult<void>> => {
    try {
      const validated = enableGitHubActionsSchema.parse(params);

      // Check license access
      const access = licenseService.canUseAutoDeploy();
      if (!access.allowed) {
        return {
          success: false,
          error: access.reason || 'GitHub Actions deployment requires a license.'
        };
      }

      await githubActionsService.enableGitHubActions(validated);
      return { success: true, data: undefined };
    } catch (error) {
      console.error('Error enabling GitHub Actions:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Disable GitHub Actions deployment
  ipcMain.handle('github-actions:disable', async (_event, params): Promise<ApiResult<void>> => {
    try {
      const validated = disableGitHubActionsSchema.parse(params);
      await githubActionsService.disable(validated.serverId, validated.appName);
      return { success: true, data: undefined };
    } catch (error) {
      console.error('Error disabling GitHub Actions:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Get GitHub Actions configuration
  ipcMain.handle('github-actions:get-config', async (_event, params): Promise<ApiResult<GitHubActionsConfig | null>> => {
    try {
      const validated = getConfigSchema.parse(params);
      const config = githubActionsService.getConfig(validated.serverId, validated.appName);
      return { success: true, data: config };
    } catch (error) {
      console.error('Error getting GitHub Actions config:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Check if GitHub Actions is enabled
  ipcMain.handle('github-actions:is-enabled', async (_event, params): Promise<ApiResult<boolean>> => {
    try {
      const validated = getConfigSchema.parse(params);
      const isEnabled = githubActionsService.isEnabled(validated.serverId, validated.appName);
      return { success: true, data: isEnabled };
    } catch (error) {
      console.error('Error checking GitHub Actions status:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Get workflow runs
  ipcMain.handle('github-actions:get-workflow-runs', async (_event, params): Promise<ApiResult<WorkflowRun[]>> => {
    try {
      const validated = getWorkflowRunsSchema.parse(params);
      const runs = await githubActionsService.getWorkflowRuns(
        validated.serverId,
        validated.appName,
        {
          per_page: validated.perPage,
          page: validated.page,
        }
      );
      return { success: true, data: runs };
    } catch (error) {
      console.error('Error getting workflow runs:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Trigger manual deployment
  ipcMain.handle('github-actions:trigger-deploy', async (_event, params): Promise<ApiResult<void>> => {
    try {
      const validated = triggerManualDeploySchema.parse(params);

      // Check license access
      const access = licenseService.canUseAutoDeploy();
      if (!access.allowed) {
        return {
          success: false,
          error: access.reason || 'Manual deployment requires a license.'
        };
      }

      await githubActionsService.triggerManualDeploy(validated.serverId, validated.appName);
      return { success: true, data: undefined };
    } catch (error) {
      console.error('Error triggering manual deployment:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Sync workflow file
  ipcMain.handle('github-actions:sync-workflow', async (_event, params): Promise<ApiResult<{ synced: boolean; message: string }>> => {
    try {
      const validated = syncWorkflowSchema.parse(params);
      const result = await githubActionsService.syncWorkflow(validated.serverId, validated.appName);
      return { success: true, data: result };
    } catch (error) {
      console.error('Error syncing workflow:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });

  // Update configuration
  ipcMain.handle('github-actions:update-config', async (_event, params): Promise<ApiResult<void>> => {
    try {
      const validated = updateConfigSchema.parse(params);
      await githubActionsService.updateConfig(
        validated.serverId,
        validated.appName,
        validated.updates
      );
      return { success: true, data: undefined };
    } catch (error) {
      console.error('Error updating GitHub Actions config:', error);
      return {
        success: false,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  });
}
